-- NATURA VIDA V7.2.1
-- Importación histórica desde Mi Negocio
-- Fuente: backup_2026-07-09 22_28.mn
--
-- IMPORTANTE:
-- 1) Inserta clientes y ventas históricas.
-- 2) NO modifica el stock actual.
-- 3) Es idempotente: puede ejecutarse nuevamente sin duplicar ventas.
-- 4) Si un cliente ya existe con el mismo nombre, reutiliza ese registro.
-- 5) El respaldo recibido contiene 0 números de celular; no se inventan teléfonos.

begin;

create temporary table if not exists nv_mn_client_map (
  legacy_id text primary key,
  actual_id text not null
) on commit drop;

truncate table nv_mn_client_map;

do $nv_import$
