  v_admin_id uuid;
  v_admin_name text;
  v_client jsonb;
  v_sale jsonb;
  v_sale_payload jsonb;
  v_actual_client_id text;
begin
  select u.id
    into v_admin_id
  from auth.users u
  where lower(coalesce(u.email,'')) = lower('naturavida.bo@gmail.com')
  order by u.created_at
  limit 1;

