    select p.id
      into v_admin_id
    from public.profiles p
    where lower(coalesce(p.role,'')) = 'administrador'
      and lower(coalesce(p.status,'')) = 'activo'
    order by p.created_at
    limit 1;
  end if;

  if v_admin_id is null then
    raise exception 'No se encontró el usuario administrador de Natura Vida.';
  end if;

