    v_actual_client_id := null;

    select c.id
      into v_actual_client_id
    from public.clients c
    where c.owner_user_id = v_admin_id
      and regexp_replace(
            translate(lower(trim(c.name)), 'áéíóúüñ.', 'aeiouun '),
            '\s+', ' ', 'g'
          )
          =
          regexp_replace(
            translate(lower(trim(coalesce(v_client->>'name',''))), 'áéíóúüñ.', 'aeiouun '),
            '\s+', ' ', 'g'
          )
    order by c.created_at
    limit 1;

    if v_actual_client_id is null then
      v_actual_client_id := v_client->>'id';

      insert into public.clients(
        id, owner_user_id, name, phone, price_group_id, payload, created_at, updated_at
      ) values (
        v_actual_client_id,
        v_admin_id,
        coalesce(v_client->>'name','Sin nombre'),
        coalesce(v_client->>'phone',''),
        coalesce(v_client->>'priceGroupId',''),
        v_client || jsonb_build_object(
          'ownerUserId', v_admin_id::text,
          'syncStatus', 'cloud'
        ),
        now(),
        now()
      )
      on conflict (id) do update set
        owner_user_id = excluded.owner_user_id,
        name = excluded.name,
        phone = case
          when coalesce(public.clients.phone,'') = '' then excluded.phone
          else public.clients.phone
        end,
        price_group_id = case
          when coalesce(public.clients.price_group_id,'') = '' then excluded.price_group_id
          else public.clients.price_group_id
        end,
        payload = coalesce(public.clients.payload,'{}'::jsonb) || excluded.payload,
        updated_at = now();
    else
      update public.clients
      set payload = coalesce(payload,'{}'::jsonb) || v_client || jsonb_build_object(
            'ownerUserId', v_admin_id::text,
            'syncStatus', 'cloud'
          ),
          updated_at = now()
      where id = v_actual_client_id;
    end if;

