h","paymentStatus":"paid","legacyPaymentMethod":"DEPOSITO BANCARIO","type":"wholesale","role":"Administrador","sellerId":null,"sellerName":"","groupId":null,"groupName":null,"items":[{"productId":"legacy_mn_200","legacyProductName":"ML ACEITE DE COCO 200ML","productName":"Aceite de Coco 200 ml","category":"Importado Mi Negocio","qty":15,"unitCost":28.5,"unitPrice":49.0,"subtotal":735.0,"profit":307.5,"historicalItem":true},{"productId":"legacy_mn_500_vidrio","legacyProductName":"PIEZA ACEITE DE COCO 500ML VIDRIO","productName":"Aceite de Coco 500 ml / Frasco VIDRIO","category":"Importado Mi Negocio","qty":15,"unitCost":85.0,"unitPrice":104.0,"subtotal":1560.0,"profit":285.0,"historicalItem":true}],"total":2295.0,"sellerProfit":0,"historicalGrossProfit":592.5,"clientId":"cli_mn_8ec39cbcad177048","clientName":"BIOMUJER","canonicalClientName":"BIOMUJER","clientPhone":"","clientAddress":"Entrega 29/06/26","date":1782755041000,"createdAtIso":"2026-06-29T13:44:01-04:00","syncStatus":"cloud","source":"Mi Negocio","historicalImport":true,"affectsStock":false,"legacyFolio":75,"legacyStatus":1,"legacyLabel":"DEPOSITO BANCARIO","legacyNotes":"Entrega 29/06/26"}]$nv_sales$::jsonb)
  loop
    select actual_id
      into v_actual_client_id
    from nv_mn_client_map
    where legacy_id = v_sale->>'clientId';

    v_sale_payload := v_sale || jsonb_build_object(
      'clientId', coalesce(v_actual_client_id, v_sale->>'clientId'),
      'sellerId', v_admin_id::text,
      'sellerName', v_admin_name,
      'syncStatus', 'cloud',
      'historicalImport', true,
      'affectsStock', false
    );

    insert into public.sales(
      id, seller_user_id, seller_name, client_name, client_phone,
      sale_type, total, seller_profit, payload, created_at, updated_at
    ) values (
      v_sale->>'id',
      v_admin_id,
      v_admin_name,
      coalesce(v_sale->>'clientName','Sin nombre'),
      coalesce(v_sale->>'clientPhone',''),
      coalesce(v_sale->>'type','unit'),
      coalesce((v_sale->>'total')::numeric,0),
      0,
      v_sale_payload,
      (v_sale->>'createdAtIso')::timestamptz,
      (v_sale->>'createdAtIso')::timestamptz
    )
    on conflict (id) do update set
      seller_user_id = excluded.seller_user_id,
      seller_name = excluded.seller_name,
      client_name = excluded.client_name,
      client_phone = excluded.client_phone,
      sale_type = excluded.sale_type,
      total = excluded.total,
      payload = excluded.payload,
      created_at = excluded.created_at,
      updated_at = now();
  end loop;
end
$nv_import$;

commit;

-- VERIFICACIÓN INMEDIATA
select
  count(*) as ventas_importadas,
  coalesce(sum(total),0) as total_importado
from public.sales
where id like 'sale_mn_%';

select
  count(*) as clientes_marcados_como_importados
from public.clients
where coalesce(payload->>'source','') = 'Mi Negocio';

select
  min(created_at) as primera_venta,
  max(created_at) as ultima_venta
from public.sales
where id like 'sale_mn_%';
